head.script:
scwin.params = "";
scwin.odrNo = ""
scwin.tabSeq = ""
scwin.clickTimer = null; // 클릭 타이머 변수

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.params = $c.data.getParameter();

    if (!$c.util.isEmpty(scwin.params["odrNo"])) {
        scwin.odrNo = scwin.params["odrNo"];
    }

    if (!$c.util.isEmpty(scwin.params["tabSeq"])) {
        scwin.tabSeq = scwin.params["tabSeq"];
    }

    //scwin.f_DivOdrMasterInfo(); TOBE에서는 바인딩으로 바꿈 
    grp_cntrDetail.setStyle("display", "none");

    const codeOptions = [
        { grpCd: "SD113", compID: "acb_cnd_odrKndCd" } //오더종류
    ];
    $c.data.setCommonCode(codeOptions);

    if (scwin.odrNo != "" && scwin.tabSeq == "1") {
        ed_odrNo.setValue(scwin.odrNo);
        scwin.f_chkContainer()
        scwin.f_Retrieve();
        scwin.f_RetrieveCNTRDetail();
    }
    else if (scwin.odrNo != "" && scwin.tabSeq == "") {
        ed_odrNo.setValue(scwin.odrNo);
        scwin.f_chkContainer()
        scwin.f_Retrieve();
    }

    //테스트데이터
    //if (ed_odrNo.getValue() == "") {
    //    ed_odrNo.setValue("DCX2005110002");
    //}
};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function () {
    let dltStr = "dlt_commonCodeSD113"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    let dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
    $c.data.dataListFilter(dlt, "fltrCd1 == 'C' && fltrCd3 == '1'");  //$c.data.dataListFilter 함수를 이용해서 필터
};

//-------------------------------------------------------------------------
// 컨테이너 체크
//-------------------------------------------------------------------------
scwin.f_chkContainer = function () {
    var conOdrNo = ed_odrNo.getValue().substring(1, 3);
    var bOdrNO = ed_odrNo.getValue().substring(1, 2);

    if (conOdrNo == "CA" || conOdrNo == "CB" || conOdrNo == "CP") {
        scwin.f_odrContainer(ed_odrNo.getValue());
    } else if (bOdrNO == "B") {
        scwin.f_odrNoDetail(ed_odrNo.getValue());
    }
};

//-------------------------------------------------------------------------
// 컨테이너오더 호출
//-------------------------------------------------------------------------
scwin.f_odrContainer = function () {
    let strUrl = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_11t.xml"
    let programId = "sd_402_01_11t.jsp";    

    let paramObj = {
        odrNo: ed_odrNo.getValue()
    };

    $c.win.openMenu("컨테이너오더", strUrl, programId, paramObj);
};

//-------------------------------------------------------------------------
// GRID에서 선택된 odrNo 세부정보 확인 : 해당 odrNo 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_odrNoDetail = function (odrNo) {
    let strUrl = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_02t.xml"
    let programId = "sd_402_01_02t.jsp";

    let paramObj = {
        odrNo: odrNo
    };

    $c.win.openMenu("벌크오더", strUrl, programId, paramObj);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (ed_odrNo.getValue() == "") {
        await $c.win.alert("오더번호는 필수 조회 조건 입니다.");
    }
    //scwin.f_DivOdrMasterInfo(); TOBE에서는 바인딩으로 바꿈 

    $c.sbm.execute(sbm_retrieve);

    grp_cntrDetail.setStyle("display", "none");
};

//-------------------------------------------------------------------------
// 검색조건 초기화 & 초기값 세팅
//-------------------------------------------------------------------------
scwin.f_SetInitCondVal = function () {
    ed_odrNo.setValue("");
};

//-------------------------------------------------------------------------
// GRID에서 선택된 오더 세부정보 확인 : 해당 오더유형별 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_containerDetail = function (row) {
    let strUrl = "/ui/ds/as/cstmrsrvc/coafmgnt/as_102_01_02b.xml"
    let programId = "as_102_01_02b.jsp";
    let cntrNo = "";

    if (row % 2 == 0) {
        if (ds_cntrPerWrkPrst.getCellData(row, "cntrNo") == "미지정") {
            $c.win.alert("미지정된 컨테이너는 조회할 수 없습니다.");
            return false;
        }
        cntrNo = ds_cntrPerWrkPrst.getCellData(row, "cntrNo");
    } else {
        if (ds_cntrPerWrkPrst.getCellData(row - 1, "cntrNo") == "미지정") {
            $c.win.alert("미지정된 컨테이너는 조회할 수 없습니다.");
            return false;
        }
        cntrNo = ds_cntrPerWrkPrst.getCellData(row - 1, "cntrNo");
    }

    let paramObj = {
        cntrNo: cntrNo
    };

    $c.win.openMenu("컨테이너화물추적", strUrl, programId, paramObj);
};

//--------------------------------
// 작업경로 변경 팝업
//--------------------------------
scwin.f_workPathMod = async function () {
    if (ds_cntrPerWrkPrst.getRowCount() == 0) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_056, "대상물량")); // 데이터 을(를) 삭제하시겠습니까? 
        return;
    }

    let row = -1;
    for (var i = 0; i < ds_cntrPerWrkPrst.getRowCount(); i++) {
        if (ds_cntrPerWrkPrst.getCellData(i, "chk") == 1) {
            row = i;
            break;
        }
    }

    if (row == -1) {
        $c.win.alert("작업경로를 바꾸기를 원하는 컨테이너를 선택하여 주십시오.");
        return false;
    }

    let cntrSeq = "";

    if (row % 2 == 0) {
        if (ds_cntrPerWrkPrst.getCellData(row, "cntrNo") == "미지정") {
            $c.win.alert("미지정된 컨테이너는 조회할 수 없습니다.");
            return false;
        }
        cntrSeq = ds_cntrPerWrkPrst.getCellData(row, "cntrSeq"); //컨테이너seq
    } else {
        if (ds_cntrPerWrkPrst.getCellData(row - 1, "cntrNo") == "미지정") {
            $c.win.alert("미지정된 컨테이너는 조회할 수 없습니다.");
            return false;
        }
        cntrSeq = ds_cntrPerWrkPrst.getCellData(row - 1, "cntrSeq"); //컨테이너seq
    }


    let win_url = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_26p.xml";

    let arrParam = {
        odrNo: ed_odrNo.getValue().trim() //오더번호
        , cntrSeq: cntrSeq
    };

    let opts = {
        id: "op_202_02_26p",
        popupName: "작업경로상세정보변경(컨테이너)",
        modal: true,
        type: "browserPopup",
        width: 1200,
        height: 800
        //title : ""
    };

    let ret = await $c.win.openPopup(win_url, opts, arrParam);

    if (ret == 1) {
        scwin.f_Retrieve(); //재조회
    }
};

//-------------------------------------------------------------------------
// 컨테이너 상세정보 조회 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_RetrieveCNTRDetail = function () {
    $c.sbm.execute(sbm_retrieveDetail);

    grp_cntrDetail.setStyle("display", "");
};

//-------------------------------------------------------------------------
// function name : f_openPopUpOdrNo	- 2006.04.25 create by kim tae won
// function desc : 오더번호검색 팝업열기
//-------------------------------------------------------------------------   
scwin.f_openPopUpOdrNo = async function () {
    let win_url = "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_31p.xml";

    var args = new Array();
    args[0] = ed_cnd_cntrNo.getValue().trim();   //컨테이너번호
    args[1] = acb_cnd_odrKndCd.getValue(); //오더종류

    let opts = {
        id: "sd_402_01_31p",
        popupName: "오더검색",
        modal: true,
        type: "browserPopup",
        width: 820,
        height: 450,
        title: "오더검색팝업"
    };

    const ret = await $c.win.openPopup(win_url, opts, args);

    if (ret != null) {
        if (ret[0] != "N/A") {
            ed_odrNo.setValue(ret[0]); // 오더번호
        }
    }
};

//-------------------------------------------------------------------------
// 조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    tbx_totalRows1.setValue($c.gus.cfInsertComma(ds_qtyWrkInfo.getRowCount()));

    if (ds_odrMasterInfo.getRowCount() == 0) {
        $c.win.alert("오더마스터 정보가 조회된 데이터가 없습니다.");
        tbx_odrNo.setValue("");
    } else {
        ds_odrMasterInfo.setRowPosition(0);

        //상/하차담당자
        let onPicNm = ds_odrMasterInfo.getCellData(0, "onPicNm") + '/' + ds_odrMasterInfo.getCellData(0, "offPicNm");
        ds_odrMasterInfo.setCellData(0, "onPicNm", onPicNm);

        //오더/배차담당자
        let odrPicNm = ds_odrMasterInfo.getCellData(0, "odrPicNm") + '/' + ds_odrMasterInfo.getCellData(0, "alloccarPicNm");
        ds_odrMasterInfo.setCellData(0, "odrPicNm", odrPicNm);

        tbx_odrNo.setValue("- " + ed_odrNo.getValue() + "[" + ds_odrMasterInfo.getCellData(0, "selfClsNm") + "]");
    }
};

//-------------------------------------------------------------------------
// 상세조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieveDetail_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    tbx_totalRows2.setValue($c.gus.cfInsertComma(ds_cntrPerWrkPrst.getRowCount()));

    if (ds_cntrPerWrkPrst.getRowCount() == 0) {
        $c.win.alert("컨테이너별 작업진행이 조회된 데이터가 없습니다.");
    } else {
        for (var i = 0; i < ds_cntrPerWrkPrst.getRowCount(); i++) {
            // Mask={Decode(tointeger((currow-1)/1)-tointeger(tointeger((currow-1)/1)/2)*2,1,Right(node1,8),0,Right(node1,5))}

            for (var j = 1; j <= 25; j++) {
                scwin.gr_cntrPerWrkPrstSetCellStyle(i, "node" + j);
            }
        }
    }
};

//-------------------------------------------------------------------------
// CNTR별 작업진행 그리드 cell color SET
//-------------------------------------------------------------------------
scwin.gr_cntrPerWrkPrstSetCellStyle = function (rowIdx, colId) {
    if (ds_cntrPerWrkPrst.getCellData(rowIdx, colId) == "") return;

    let node = ds_cntrPerWrkPrst.getCellData(rowIdx, colId).substring(0, 1);

    if (node == "Y") {
        gr_cntrPerWrkPrst.setCellStyle(rowIdx, colId, "color", "blue");
    } else if (node == "Z") {
        gr_cntrPerWrkPrst.setCellStyle(rowIdx, colId, "color", "red");
    }
};

//-------------------------------------------------------------------------
// CNTR별 작업진행 그리드 oncellclick
//-------------------------------------------------------------------------
scwin.gr_cntrPerWrkPrst_oncellclick = function (rowIndex, columnIndex, columnId) {
    // 클릭 이벤트 처리
    if (scwin.clickTimer) {
        $p.clearTimeout(scwin.clickTimer); // 기존 타이머 제거
    }

    scwin.clickTimer = $p.setTimeout(function () {
        console.log("셀 클릭 이벤트 발생");
        // 클릭 이벤트 로직 실행

        if (columnId == "chk") {
            var checkedCount = 0;

            for (var i = 0; i < ds_cntrPerWrkPrst.getRowCount(); i++) {
                if (ds_cntrPerWrkPrst.getCellData(i, "chk") == 1) {
                    checkedCount++;
                }
            }

            if (checkedCount > 2) {
                $c.win.alert("1개의 컨테이너만 선택하여 주십시오.");
                if (ds_cntrPerWrkPrst.getCellData(rowIndex, "chk") == 1) {
                    ds_cntrPerWrkPrst.setCellData(rowIndex, "chk", 0);
                }
                return false;
            }

            if (ds_cntrPerWrkPrst.getCellData(rowIndex, "chk") == 1 && rowIndex % 2 == 0) {
                ds_cntrPerWrkPrst.setCellData(rowIndex + 1, "chk", 1);
            }

            if (ds_cntrPerWrkPrst.getCellData(rowIndex, "chk") == 1 && rowIndex % 2 == 1) {
                ds_cntrPerWrkPrst.setCellData(rowIndex - 1, "chk", 1);
            }

            if (ds_cntrPerWrkPrst.getCellData(rowIndex, "chk") == 0 && rowIndex % 2 == 0) {
                ds_cntrPerWrkPrst.setCellData(rowIndex + 1, "chk", 0);
            }

            if (ds_cntrPerWrkPrst.getCellData(rowIndex, "chk") == 0 && rowIndex % 2 == 1) {
                ds_cntrPerWrkPrst.setCellData(rowIndex - 1, "chk", 0);
            }
        }

        scwin.clickTimer = null; // 타이머 초기화
    }, 300); // 더블 클릭과 구분하기 위해 300ms 대기
};

//-------------------------------------------------------------------------
// CNTR별 작업진행 그리드 oncelldblclick
//-------------------------------------------------------------------------
scwin.gr_cntrPerWrkPrst_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    // 더블 클릭 이벤트 처리
    if (scwin.clickTimer) {
        $p.clearTimeout(scwin.clickTimer); // 클릭 타이머 제거
        scwin.clickTimer = null; // 타이머 초기화
    }

    console.log("셀 더블 클릭 이벤트 발생");

    // 더블 클릭 이벤트 로직 실행
    if (columnId == "cntrNo") {
        // 오더세부사항 조회 
        scwin.f_containerDetail(rowIndex);
    }
};

//-------------------------------------------------------------------------
// 대문자입력
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

//-------------------------------------------------------------------------
// 컨테이너번호 포커스 OUT 
//-------------------------------------------------------------------------
scwin.ed_cnd_cntrNo_onblur = function (e) {
    //검색조건 컨테이너번호 입력 체크
    if (!$c.gus.cfIsNull(ed_cnd_cntrNo.getValue().trim()))
        scwin.f_openPopUpOdrNo();
};
